def p1_nn(doc):
    prompt = "Spørsmål: {question}\n\nSvaralternativ:{choices}\n\nSvar:"
    choices = "".join(
        list(map(lambda choice: f"\n- {choice}", doc["mc1_targets"]["choices"]))
    )
    return prompt.format(question=doc["question"], choices=choices)

